import React, { useState, useEffect } from 'react';
import axios from 'axios';

const App = () => {
  const [sessions, setSessions] = useState([]);
  const [interval, setInterval] = useState('');
  const [status, setStatus] = useState('');

  useEffect(() => {
    axios.get('/api/sessions')
      .then(response => setSessions(response.data))
      .catch(error => console.error(error));
  }, []);

  const handleFilter = () => {
    axios.get(`/api/sessions?interval=${interval}&status=${status}`)
      .then(response => setSessions(response.data))
      .catch(error => console.error(error));
  }

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="bg-white p-4 rounded shadow">
        <div className="flex justify-between mb-4">
          <h2 className="text-lg font-bold">Session Manager</h2>
          <button className="bg-blue-500 hover:bg-blue-700 text-white font-bold py-2 px-4 rounded">Logout</button>
        </div>
        <div className="mb-4">
          <select className="bg-gray-50 border border-gray-300 text-gray-900 text-sm rounded-lg focus:ring-blue-500 focus:border-blue-500 block w-full p-2.5" value={interval} onChange={(e) => setInterval(e.target.value)}>
            <option value="">Select Interval</option>
            <option value="all">All</option>
            <option value="1h">Last 1 hour</option>
            <option value="24h">Last 24 hours</option>
            <option value="week">Last week</option>
          </select>
        </div>
        <div className="mb-4">
          <select className="bg-gray-50 border border-gray-300 text-gray-900 text-sm rounded-lg focus:ring-blue-500 focus:border-blue-500 block w-full p-2.5" value={status} onChange={(e) => setStatus(e.target.value)}>
            <option value="">Session Status</option>
            <option value="active">Active</option>
            <option value="inactive">Inactive</option>
          </select>
        </div>
        <button className="bg-blue-500 hover:bg-blue-700 text-white font-bold py-2 px-4 rounded" onClick={handleFilter}>Apply</button>
        <div className="mt-4">
          <table className="w-full border-collapse border border-slate-400">
            <thead>
              <tr>
                <th className="bg-gray-50 border border-gray-300 px-4 py-2 text-sm font-bold">Session ID</th>
                <th className="bg-gray-50 border border-gray-300 px-4 py-2 text-sm font-bold">User ID</th>
                <th className="bg-gray-50 border border-gray-300 px-4 py-2 text-sm font-bold">Interval</th>
                <th className="bg-gray-50 border border-gray-300 px-4 py-2 text-sm font-bold">Status</th>
              </tr>
            </thead>
            <tbody>
              {sessions.map(session => (
                <tr key={session.id} className="border border-gray-300">
                  <td className="px-4 py-2 text-sm">{session.id}</td>
                  <td className="px-4 py-2 text-sm">{session.userId}</td>
                  <td className="px-4 py-2 text-sm">{session.interval}</td>
                  <td className="px-4 py-2 text-sm">{session.status}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default App;
